#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, X; scanf("%lld %lld", &N, &X);
        long long half = N/2;
        long long maxDist = (N+1)/2; // ceil(N/2)
        if(X < 1 || X > maxDist || X > 26){
            printf("-1\n");
            continue;
        }
        char *s = (char*)malloc(N+1);
        memset(s, 'a', N);
        s[N] = '\0';
        long long use = X < half ? X : half;
        for(long long i=0;i<use;i++){
            s[i] = s[N-1-i] = 'a' + i;
        }
        if(N%2==1 && X>half){
            s[half] = 'a' + X - 1;
        }
        printf("%s\n", s);
        free(s);
    }
    return 0;
}

