const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const X = Number(input[idx++]);
  const half = Math.floor(N / 2);
  const maxDist = Math.floor((N + 1) / 2); // ceil(N/2)
  if (X < 1 || X > maxDist || X > 26) {
    out.push('-1');
    continue;
  }
  const arr = new Array(N).fill('a');
  const use = Math.min(X, half);
  for (let i = 0; i < use; i++) {
    const ch = String.fromCharCode(97 + i);
    arr[i] = ch;
    arr[N - 1 - i] = ch;
  }
  if (N % 2 === 1 && X > half) {
    arr[half] = String.fromCharCode(97 + X - 1);
  }
  out.push(arr.join(''));
}
